import React from "react"
import Layout from "../components/Layout"
import { graphql, Link } from "gatsby"
import moment from "moment-timezone"

export default function Home({ data }) {
  const { title } = data.site.siteMetadata
  const { posts } = data.blog
  
  return (
    <Layout>
      <div>
        <h1>{title}</h1>
        <p>A minimalistic blog to catalogue the thoughts and beliefs of Ricky Dodd (<a href="https://www.github.com/rickydodd/">GitHub profile</a>). Any thoughts or beliefs posted on this blog are the thoughts or beliefs of Ricky Dodd, and these thoughts or beliefs do not represent the thoughts or beliefs of any other person (or entity), whether they associate with Ricky Dodd in a professional or private context, unless otherwise stated by this person (or entity).</p>
        
        <h2>Posts</h2>

        {posts.map(post => (
          <article key={post.id}>
            <Link to={post.fields.slug}>
              <h3>{post.frontmatter.title}</h3>
            </Link>
            <small>{post.frontmatter.author}, { moment(post.frontmatter.date).fromNow() }</small>
            <p>{post.excerpt}</p>
          </article>
        ))}
      </div>
    </Layout>
  )
}

export const pageQuery = graphql`
  query IndexQuery {
    site {
      siteMetadata {
        title
        siteUrl
        description
      }
    }

    blog: allMarkdownRemark (sort: {fields: [frontmatter___date] order: DESC}) {
      posts: nodes {
        fields {
          slug
        }
        frontmatter {
          date
          title
          author
        }
        excerpt
        id
      }
    }
  }
`
